/* ════════════════════════════════════════════════════
   STORAGE — wipe all old keys, use fresh key gos_tt_v6
   ════════════════════════════════════════════════════ */
const SK = "gos_tt_v6";

/* On first load, clear ALL old versions so there's no conflict */
["gos_tt_v1","gos_tt_v2","gos_tt_v3","gos_tt_v4","gos_tt_v5"].forEach(k=>{
  try{ localStorage.removeItem(k); }catch(e){}
});

function loadStore(){
  try{ return JSON.parse(localStorage.getItem(SK)||"{}"); }catch{ return {}; }
}
function saveStore(d){ localStorage.setItem(SK, JSON.stringify(d)); }
function todayKey(){ return new Date().toISOString().slice(0,10); }
function fmtTime(ts){ return ts ? new Date(ts).toLocaleTimeString([],{hour:"2-digit",minute:"2-digit"}) : "—"; }
function fmtDur(ms){
  if(!ms||ms<=0) return "0h 0m";
  const m=Math.floor(ms/60000);
  return `${Math.floor(m/60)}h ${m%60}m`;
}

/* ── Each day stores an array of sessions ─────────────
   session = { clockIn, clockOut, lunchMin, travelHours, travelMiles, modifiedLog[] }
   ─────────────────────────────────────────────────── */
function getActiveSesh(day){
  if(!day?.sessions?.length) return null;
  const last=day.sessions[day.sessions.length-1];
  return (!last.clockOut) ? last : null;
}
function netMs(s){
  if(!s?.clockIn||!s?.clockOut) return 0;
  return Math.max(0, s.clockOut - s.clockIn - (s.lunchMin||0)*60000);
}
function dayNetMs(day){
  if(!day?.sessions) return 0;
  return day.sessions.reduce((acc,s)=>acc+netMs(s),0);
}

function buildCSV(empName,days,start,end){
  const rows=[["Date","Employee","Session","Clock In","Clock Out","Gross","Lunch(min)","Net Work","Travel Hrs","Travel Mi","Modified?"]];
  let totNet=0,totTH=0,totTM=0;
  const sd=new Date(start+"T00:00:00"),ed=new Date(end+"T23:59:59");
  Object.keys(days).sort().forEach(k=>{
    const d=new Date(k+"T12:00:00");
    if(d<sd||d>ed) return;
    const day=days[k];
    if(!day.sessions?.length) return;
    day.sessions.forEach((s,i)=>{
      if(!s.clockOut) return;
      const nm=netMs(s); totNet+=nm;
      const isLast=i===day.sessions.length-1;
      if(isLast){ totTH+=(parseFloat(s.travelHours)||0); totTM+=(parseFloat(s.travelMiles)||0); }
      rows.push([k,empName,`Session ${i+1}`,fmtTime(s.clockIn),fmtTime(s.clockOut),
        fmtDur(s.clockOut-s.clockIn),s.lunchMin||0,fmtDur(nm),
        isLast?(s.travelHours||0):"—",isLast?(s.travelMiles||0):"—",
        s.modifiedLog?.length?"Yes":"No"]);
    });
  });
  rows.push([],["TOTALS","","","","","","",fmtDur(totNet),totTH.toFixed(2),totTM.toFixed(2),""]);
  return rows.map(r=>r.map(c=>`"${c}"`).join(",")).join("\n");
}

function thisWeekRange(){
  const now=new Date(),day=now.getDay(),d=day===0?6:day-1;
  const mon=new Date(now); mon.setDate(now.getDate()-d);
  return {start:mon.toISOString().slice(0,10),end:now.toISOString().slice(0,10)};
}
function lastWeekRange(){
  const now=new Date(),day=now.getDay(),d=day===0?2:day===6?1:day+2;
  const fri=new Date(now); fri.setDate(now.getDate()-d);
  const mon=new Date(fri); mon.setDate(fri.getDate()-4);
  return {start:mon.toISOString().slice(0,10),end:fri.toISOString().slice(0,10)};
}

async function sendEmail({serviceId,templateId,publicKey,toEmail,empName,csvContent,weekStart,weekEnd}){
  const r=await fetch("https://api.emailjs.com/api/v1.0/email/send",{
    method:"POST",headers:{"Content-Type":"application/json"},
    body:JSON.stringify({service_id:serviceId,template_id:templateId,user_id:publicKey,
      template_params:{to_email:toEmail,employee:empName,
        week_start:weekStart,week_end:weekEnd,csv_data:csvContent,sent_at:new Date().toLocaleString()}})
  });
  if(!r.ok) throw new Error(`EmailJS ${r.status}`);
}

/* ── UI primitives ── */
function Btn({label,onClick,color=C.blue,disabled,sm,full=true,style={}}){
  return(
    <button onClick={onClick} disabled={disabled} style={{
      display:"block",width:full?"100%":"auto",background:disabled?"#bbb":color,
      color:"#fff",border:"none",borderRadius:12,padding:sm?"11px 20px":"16px 24px",
      fontSize:sm?14:17,fontWeight:700,cursor:disabled?"not-allowed":"pointer",
      letterSpacing:.4,...style
    }}>{label}</button>
  );
}
function Card({children,style={}}){
  return <div style={{background:"#fff",borderRadius:18,padding:20,
    boxShadow:"0 2px 14px rgba(0,0,0,.07)",marginBottom:16,...style}}>{children}</div>;
}
function Row({label,value,accent}){
  return(
    <div style={{display:"flex",justifyContent:"space-between",
      padding:"9px 0",borderBottom:`1px solid ${C.border}`,fontSize:14}}>
      <span style={{color:C.sub}}>{label}</span>
      <span style={{fontWeight:700,color:accent||C.text}}>{value}</span>
    </div>
  );
}
function Inp({label,type="text",value,onChange,placeholder,step,id}){
  return(
    <div style={{marginBottom:12}}>
      {label&&<div style={{fontSize:13,fontWeight:700,color:C.sub,marginBottom:5}}>{label}</div>}
      <input id={id} type={type} value={value} onChange={onChange}
        placeholder={placeholder} step={step}
        style={{width:"100%",padding:"12px 14px",fontSize:15,borderRadius:10,
          border:`2px solid ${C.border}`,boxSizing:"border-box",background:"#fff"}}/>
    </div>
  );
}
function Shell({children,onBack,title,employee,onSignOut,toast}){
  return(
    <div style={{minHeight:"100vh",background:C.gray,fontFamily:"system-ui,sans-serif",
      maxWidth:440,margin:"0 auto",display:"flex",flexDirection:"column"}}>
      <div style={{background:`linear-gradient(135deg,${C.dark} 0%,${C.blue} 100%)`,
        padding:"16px 18px",display:"flex",alignItems:"center",gap:12,
        boxShadow:"0 2px 8px rgba(0,0,0,.2)",position:"sticky",top:0,zIndex:10}}>
        {onBack&&<button onClick={onBack} style={{background:"rgba(255,255,255,.18)",
          border:"none",color:"#fff",borderRadius:8,padding:"6px 14px",
          cursor:"pointer",fontSize:20,fontWeight:700,lineHeight:1}}>‹</button>}
        <div style={{flex:1}}>
          {title&&<div style={{color:"#fff",fontWeight:800,fontSize:17}}>{title}</div>}
          {employee&&<div style={{color:"rgba(255,255,255,.75)",fontSize:13}}>{employee}</div>}
        </div>
        {onSignOut&&<button onClick={onSignOut} style={{background:"rgba(255,255,255,.18)",
          border:"none",color:"#fff",borderRadius:8,padding:"6px 12px",
          cursor:"pointer",fontSize:12,fontWeight:700}}>Sign Out</button>}
      </div>
      {toast&&<div style={{background:toast.startsWith("❌")?C.red:toast.startsWith("✅")?C.green:C.blue,
        color:"#fff",padding:"12px 18px",fontWeight:700,fontSize:14,textAlign:"center"}}>
        {toast}</div>}
      <div style={{flex:1,padding:"18px 16px",overflowY:"auto"}}>{children}</div>
    </div>
  );
}
function LiveClock(){
  const[now,setNow]=useState(new Date());
  useEffect(()=>{const id=setInterval(()=>setNow(new Date()),1000);return()=>clearInterval(id);},[]);
  return(
    <div style={{textAlign:"center",marginBottom:4}}>
      <div style={{color:C.sub,fontSize:13}}>
        {now.toLocaleDateString([],{weekday:"long",month:"long",day:"numeric"})}
      </div>
      <div style={{color:C.red,fontWeight:800,fontSize:24,letterSpacing:1,fontVariantNumeric:"tabular-nums"}}>
        {now.toLocaleTimeString([],{hour:"2-digit",minute:"2-digit",second:"2-digit"})}
      </div>
    </div>
  );
}
function Timer({startTs}){
  const[e,setE]=useState(Date.now()-startTs);
  useEffect(()=>{const id=setInterval(()=>setE(Date.now()-startTs),1000);return()=>clearInterval(id);},[startTs]);
  const h=Math.floor(e/3600000),m=Math.floor((e%3600000)/60000),s=Math.floor((e%60000)/1000);
  return(
    <div style={{textAlign:"center",fontSize:48,fontWeight:900,color:C.red,
      letterSpacing:3,fontVariantNumeric:"tabular-nums",lineHeight:1.1,margin:"8px 0"}}>
      {String(h).padStart(2,"0")}:{String(m).padStart(2,"0")}:{String(s).padStart(2,"0")}
    </div>
  );
}

/* ════════════════════════════════════════════════════
   APP
   ════════════════════════════════════════════════════ */
export default function App(){
  const[store,  setStore ]=useState(loadStore);
  const[screen, setScreen]=useState("splash");
  const[emp,    setEmp   ]=useState(()=>loadStore().currentEmployee||"");
  const[selEmp, setSelEmp]=useState("Select Employee...");
  const[toast,  setToast ]=useState("");
  const tRef=useRef(null);

  /* clock-out flow */
  const[lunchMin,   setLunchMin  ]=useState(0);
  const[custLunch,  setCustLunch ]=useState("");
  const[travHours,  setTravHours ]=useState("");
  const[travMiles,  setTravMiles ]=useState("");

  /* history edit */
  const[editKey, setEditKey]=useState(null);
  const[editIdx, setEditIdx]=useState(null);
  const[eCI,setECI]=useState(""); const[eCO,setECO]=useState("");
  const[eTH,setETH]=useState(""); const[eTM,setETM]=useState("");
  const[eLM,setELM]=useState("");

  /* admin */
  const[pin,       setPin      ]=useState("");
  const[unlocked,  setUnlocked ]=useState(false);
  const[aTab,      setATab     ]=useState("employees");
  const[pStart,    setPStart   ]=useState(()=>thisWeekRange().start);
  const[pEnd,      setPEnd     ]=useState(()=>thisWeekRange().end);
  const[pEmp,      setPEmp     ]=useState("");
  const[sending,   setSending  ]=useState(false);
  const[nFirst,    setNFirst   ]=useState("");
  const[nLast,     setNLast    ]=useState("");
  const[empSrch,   setEmpSrch  ]=useState("");
  const[confDel,   setConfDel  ]=useState(null);

  const employees=(store.employees?.length>0)
    ?[...store.employees].sort((a,b)=>a.localeCompare(b))
    :[...DEFAULT_EMPLOYEES].sort((a,b)=>a.localeCompare(b));

  const cfg=store.emailCfg||{serviceId:"",templateId:"",publicKey:"",managerEmail:"",autoSendFriday:false};

  function toast_(msg,dur=3500){
    setToast(msg); clearTimeout(tRef.current);
    tRef.current=setTimeout(()=>setToast(""),dur);
  }

  const upd=useCallback((patch)=>{
    setStore(p=>{const n={...p,...patch};saveStore(n);return n;});
  },[]);

  /* Add a brand-new session to a day */
  function addSesh(dayKey,sesh){
    setStore(p=>{
      const days={...(p.days||{})};
      const day={...(days[dayKey]||{sessions:[]})};
      day.sessions=[...(day.sessions||[]),sesh];
      days[dayKey]=day;
      const n={...p,days};saveStore(n);return n;
    });
  }

  /* Patch an existing session */
  const patchSesh=useCallback((dayKey,idx,patch)=>{
    setStore(p=>{
      const days={...(p.days||{})};
      const day={...(days[dayKey]||{sessions:[]})};
      const sessions=[...(day.sessions||[])];
      sessions[idx]={...sessions[idx],...patch};
      day.sessions=sessions; days[dayKey]=day;
      const n={...p,days};saveStore(n);return n;
    });
  },[]);

  function saveCfg(patch){ upd({emailCfg:{...cfg,...patch}}); }

  /* ── Derived today ── */
  const todayData = store.days?.[todayKey()]||{sessions:[]};
  const sessions  = todayData.sessions||[];
  const active    = getActiveSesh(todayData);   // null if not clocked in
  const clocked   = !!active;
  const done      = sessions.filter(s=>s.clockOut);

  /* Splash routing */
  useEffect(()=>{
    const id=setTimeout(()=>setScreen(emp?"home":"login"),2200);
    return()=>clearTimeout(id);
  },[]);

  /* 5pm reminder */
  useEffect(()=>{
    const id=setInterval(()=>{
      const n=new Date();
      if(n.getHours()===17&&n.getMinutes()===0&&clocked)
        toast_("⏰ Don't forget to clock out!");
    },60000);
    return()=>clearInterval(id);
  },[clocked]);

  /* Auto Friday email */
  useEffect(()=>{
    const id=setInterval(async()=>{
      const n=new Date();
      if(n.getDay()!==5||n.getHours()!==17||n.getMinutes()!==0) return;
      const mon=thisWeekRange().start;
      if(store.lastAutoSent===mon) return;
      const c=store.emailCfg||{};
      if(!c.serviceId||!c.templateId||!c.publicKey||!c.managerEmail||!c.autoSendFriday||!emp) return;
      const rng=thisWeekRange();
      try{
        await sendEmail({...c,toEmail:c.managerEmail,empName:emp,
          csvContent:buildCSV(emp,store.days||{},rng.start,rng.end),
          weekStart:rng.start,weekEnd:rng.end});
        upd({lastAutoSent:mon}); toast_("📧 Weekly report auto-emailed!");
      }catch(e){ toast_("❌ Auto-email failed: "+e.message,6000); }
    },30000);
    return()=>clearInterval(id);
  },[store,emp]);

  function payTotals(s,e){
    const days=store.days||{};
    let net=0,th=0,tm=0,count=0;
    const sd=new Date(s+"T00:00:00"),ed=new Date(e+"T23:59:59");
    Object.keys(days).sort().forEach(k=>{
      const d=new Date(k+"T12:00:00"); if(d<sd||d>ed) return;
      const day=days[k]; if(!day.sessions?.some(x=>x.clockOut)) return;
      net+=dayNetMs(day);
      const last=day.sessions.filter(x=>x.clockOut).at(-1);
      th+=(parseFloat(last?.travelHours)||0); tm+=(parseFloat(last?.travelMiles)||0);
      count++;
    });
    return{net,th,tm,count};
  }

  function dlCSV(name,s,e){
    const csv=buildCSV(name,store.days||{},s,e);
    const a=Object.assign(document.createElement("a"),{
      href:URL.createObjectURL(new Blob([csv],{type:"text/csv"})),
      download:`GOS_${name.replace(/ /g,"_")}_${s}_${e}.csv`
    });
    a.click(); toast_("✅ CSV downloaded!");
  }

  async function emailReport(name,s,e){
    const c=store.emailCfg||{};
    if(!c.serviceId||!c.templateId||!c.publicKey||!c.managerEmail){
      toast_("❌ Complete EmailJS setup first",5000); return;
    }
    setSending(true);
    try{
      await sendEmail({...c,toEmail:c.managerEmail,empName:name,
        csvContent:buildCSV(name,store.days||{},s,e),weekStart:s,weekEnd:e});
      toast_("✅ Emailed to "+c.managerEmail);
    }catch(e){ toast_("❌ "+e.message,5000); }
    finally{ setSending(false); }
  }

  function addEmp(){
    const f=nFirst.trim(),l=nLast.trim();
    if(!f||!l){toast_("❌ Enter both names.");return;}
    const full=`${f} ${l}`;
    if(employees.includes(full)){toast_("❌ Already exists.");return;}
    upd({employees:[...employees,full]}); setNFirst(""); setNLast("");
    toast_(`✅ ${full} added.`);
  }
  function delEmp(name){
    if(confDel!==name){setConfDel(name);return;}
    upd({employees:employees.filter(e=>e!==name)});
    if(emp===name){upd({currentEmployee:""});setEmp("");}
    setConfDel(null); toast_(`✅ ${name} removed.`);
  }

  /* ══════════════════════════════════════════════════
     SCREENS
     ══════════════════════════════════════════════════ */
  if(screen==="splash") return(
    <div style={{minHeight:"100vh",display:"flex",flexDirection:"column",
      alignItems:"center",justifyContent:"center",
      background:`linear-gradient(160deg,${C.dark} 0%,${C.blue} 55%,${C.red} 100%)`}}>
      <img src={LOGO} alt="GOS" style={{width:"80%",maxWidth:320,
        filter:"drop-shadow(0 4px 20px rgba(0,0,0,.4))"}}/>
      <div style={{marginTop:24,color:"rgba(255,255,255,.85)",fontSize:14,
        letterSpacing:3,textTransform:"uppercase",fontWeight:700}}>Employee Time Tracker</div>
      <div style={{marginTop:32,width:36,height:36,border:"4px solid rgba(255,255,255,.25)",
        borderTop:"4px solid #fff",borderRadius:"50%",animation:"spin .8s linear infinite"}}/>
      <style>{`@keyframes spin{to{transform:rotate(360deg)}}`}</style>
    </div>
  );

  if(screen==="login") return(
    <div style={{minHeight:"100vh",background:C.gray,display:"flex",flexDirection:"column",
      alignItems:"center",justifyContent:"center",padding:24,fontFamily:"system-ui,sans-serif"}}>
      <img src={LOGO} alt="GOS" style={{width:"75%",maxWidth:280,marginBottom:32}}/>
      <div style={{width:"100%",maxWidth:400}}>
        <Card>
          <div style={{fontSize:22,fontWeight:800,color:C.text,marginBottom:20,textAlign:"center"}}>Sign In</div>
          <div style={{fontSize:13,fontWeight:700,color:C.sub,marginBottom:6}}>Select Your Name</div>
          <select value={selEmp} onChange={e=>setSelEmp(e.target.value)}
            style={{width:"100%",padding:"14px 12px",fontSize:16,borderRadius:10,
              border:`2px solid ${C.border}`,background:"#fff",marginBottom:20,
              boxSizing:"border-box",WebkitAppearance:"none"}}>
            <option>Select Employee...</option>
            {employees.map(e=><option key={e}>{e}</option>)}
          </select>
          <Btn label="Sign In" color={C.red} disabled={selEmp==="Select Employee..."}
            onClick={()=>{
              setEmp(selEmp); upd({currentEmployee:selEmp}); setPEmp(selEmp); setScreen("home");
            }}/>
        </Card>
        <div style={{textAlign:"center",fontSize:12,color:C.sub,marginTop:8}}>
          You stay signed in on this device until you sign out.
        </div>
      </div>
    </div>
  );

  if(screen==="home") return(
    <Shell title="Gulf Office Systems" employee={emp} toast={toast}
      onSignOut={()=>{
        if(clocked){toast_("Please clock out before signing out.");return;}
        upd({currentEmployee:""});setEmp("");setScreen("login");
      }}>
      <LiveClock/>
      <Card style={{marginTop:10}}>
        <div style={{textAlign:"center",fontSize:18,fontWeight:800,color:C.text,marginBottom:4}}>
          {clocked?"🟢 Clocked In":"⚪ Not Clocked In"}
        </div>
        {clocked&&<>
          <div style={{textAlign:"center",fontSize:13,color:C.sub,marginBottom:10}}>
            Session {sessions.length} · started {fmtTime(active.clockIn)}
          </div>
          <Timer startTs={active.clockIn}/>
        </>}
        {done.length>0&&(
          <div style={{textAlign:"center",fontSize:13,color:C.blue,marginTop:8,fontWeight:700}}>
            Today: {fmtDur(dayNetMs(todayData))} net · {done.length} session{done.length>1?"s":""}
          </div>
        )}
      </Card>

      {/* CLOCK IN — shows whenever not actively clocked in */}
      {!clocked&&(
        <Btn label="🕐 Clock In" color={C.blue}
          onClick={()=>{
            const ts=Date.now();
            addSesh(todayKey(),{clockIn:ts,employee:emp,modifiedLog:[]});
            toast_("✅ Clocked in at "+fmtTime(ts));
          }}/>
      )}

      {clocked&&(
        <Btn label="🕔 Clock Out" color={C.red}
          onClick={()=>{
            patchSesh(todayKey(),sessions.length-1,{clockOut:Date.now()});
            setLunchMin(0);setCustLunch("");setTravHours("");setTravMiles("");
            setScreen("lunchQ");
          }}/>
      )}

      <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginTop:8}}>
        <Btn label="📋 History" color={C.dark} sm onClick={()=>setScreen("history")}/>
        <Btn label="⚙️ Admin"  color="#555"  sm onClick={()=>setScreen("admin")}/>
      </div>

      {done.length>0&&(
        <Card style={{marginTop:8,borderLeft:`4px solid ${C.blue}`}}>
          <div style={{fontWeight:800,color:C.text,marginBottom:8,fontSize:15}}>Today's Sessions</div>
          {done.map((s,i)=>(
            <div key={i} style={{marginBottom:8,paddingBottom:8,
              borderBottom:i<done.length-1?`1px solid ${C.border}`:"none"}}>
              <div style={{fontSize:12,fontWeight:700,color:C.blue,marginBottom:4}}>Session {i+1}</div>
              <Row label="In / Out" value={`${fmtTime(s.clockIn)} → ${fmtTime(s.clockOut)}`}/>
              <Row label="Lunch"    value={s.lunchMin?`${s.lunchMin} min`:"None"}/>
              <Row label="Net"      value={fmtDur(netMs(s))} accent={C.blue}/>
            </div>
          ))}
          <Row label="Total Net" value={fmtDur(dayNetMs(todayData))} accent={C.red}/>
        </Card>
      )}
    </Shell>
  );

  if(screen==="lunchQ") return(
    <Shell title="Lunch Break" toast={toast}>
      <Card>
        <div style={{fontSize:20,fontWeight:800,color:C.text,textAlign:"center",marginBottom:8}}>
          Did you take a lunch break?
        </div>
        <div style={{fontSize:13,color:C.sub,textAlign:"center",marginBottom:20}}>For this session</div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:12}}>
          <Btn label="✅ Yes" color={C.blue} onClick={()=>setScreen("lunchLen")}/>
          <Btn label="❌ No"  color={C.sub}
            onClick={()=>{patchSesh(todayKey(),sessions.length-1,{lunchMin:0});setScreen("travel");}}/>
        </div>
      </Card>
    </Shell>
  );

  if(screen==="lunchLen") return(
    <Shell title="Lunch Duration" onBack={()=>setScreen("lunchQ")} toast={toast}>
      <Card>
        <div style={{fontSize:18,fontWeight:800,color:C.text,marginBottom:20,textAlign:"center"}}>
          How long was your lunch?
        </div>
        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:10,marginBottom:16}}>
          {[[30,"30 Minutes"],[60,"1 Hour"]].map(([m,l])=>(
            <Btn key={m} label={l} sm color={lunchMin===m?C.red:C.blue} onClick={()=>setLunchMin(m)}/>
          ))}
        </div>
        <Inp label="Custom (minutes)" type="number" placeholder="e.g. 45" value={custLunch}
          onChange={e=>{setCustLunch(e.target.value);setLunchMin(parseInt(e.target.value)||0);}}/>
        <Btn label="Continue →" color={C.red} disabled={!lunchMin}
          onClick={()=>{patchSesh(todayKey(),sessions.length-1,{lunchMin});setScreen("travel");}}/>
      </Card>
    </Shell>
  );

  if(screen==="travel") return(
    <Shell title="Travel Time" onBack={()=>setScreen("lunchQ")} toast={toast}>
      <Card>
        <div style={{fontSize:18,fontWeight:800,color:C.text,marginBottom:6,textAlign:"center"}}>
          Total Travel Time Today
        </div>
        <div style={{fontSize:13,color:C.sub,textAlign:"center",marginBottom:18}}>Hours driven for work</div>
        <input type="number" step="0.25" placeholder="e.g. 1.5" value={travHours}
          onChange={e=>setTravHours(e.target.value)}
          style={{width:"100%",padding:"16px",fontSize:22,borderRadius:10,
            border:`2px solid ${C.border}`,boxSizing:"border-box",marginBottom:16,
            textAlign:"center",fontWeight:700}}/>
        <Btn label="Continue →" color={C.red}
          onClick={()=>{patchSesh(todayKey(),sessions.length-1,{travelHours:travHours||"0"});setScreen("mileage");}}/>
        <div style={{height:8}}/>
        <Btn label="No Travel Today" color={C.sub} sm
          onClick={()=>{setTravHours("0");patchSesh(todayKey(),sessions.length-1,{travelHours:"0"});setScreen("mileage");}}/>
      </Card>
    </Shell>
  );

  if(screen==="mileage") return(
    <Shell title="Travel Mileage" onBack={()=>setScreen("travel")} toast={toast}>
      <Card>
        <div style={{fontSize:18,fontWeight:800,color:C.text,marginBottom:6,textAlign:"center"}}>
          Total Miles Driven Today
        </div>
        <div style={{fontSize:13,color:C.sub,textAlign:"center",marginBottom:18}}>Total for the whole day</div>
        <input type="number" step="1" placeholder="e.g. 42" value={travMiles}
          onChange={e=>setTravMiles(e.target.value)}
          style={{width:"100%",padding:"16px",fontSize:22,borderRadius:10,
            border:`2px solid ${C.border}`,boxSizing:"border-box",marginBottom:16,
            textAlign:"center",fontWeight:700}}/>
        <Btn label="✅ Submit" color={C.red}
          onClick={()=>{patchSesh(todayKey(),sessions.length-1,{travelMiles:travMiles||"0"});setScreen("daydone");}}/>
        <div style={{height:8}}/>
        <Btn label="No Mileage" color={C.sub} sm
          onClick={()=>{setTravMiles("0");patchSesh(todayKey(),sessions.length-1,{travelMiles:"0"});setScreen("daydone");}}/>
      </Card>
    </Shell>
  );

  if(screen==="daydone"){
    const day=store.days?.[todayKey()]||{sessions:[]};
    const fin=day.sessions.filter(s=>s.clockOut);
    return(
      <Shell title="Session Complete 🎉" toast={toast}>
        <Card style={{borderTop:`4px solid ${C.blue}`}}>
          <div style={{textAlign:"center",fontSize:22,fontWeight:900,color:C.blue,marginBottom:4}}>Session saved!</div>
          <div style={{textAlign:"center",fontSize:14,color:C.sub,marginBottom:18}}>{emp}</div>
          {fin.map((s,i)=>(
            <div key={i} style={{marginBottom:10,paddingBottom:10,
              borderBottom:i<fin.length-1?`1px solid ${C.border}`:"none"}}>
              <div style={{fontSize:12,fontWeight:700,color:C.blue,marginBottom:4}}>Session {i+1}</div>
              <Row label="In / Out" value={`${fmtTime(s.clockIn)} → ${fmtTime(s.clockOut)}`}/>
              <Row label="Lunch"    value={s.lunchMin?`${s.lunchMin} min`:"None"}/>
              <Row label="Net"      value={fmtDur(netMs(s))} accent={C.blue}/>
            </div>
          ))}
          <Row label="Total Net Today" value={fmtDur(dayNetMs(day))} accent={C.red}/>
        </Card>
        <Btn label="🕐 Clock Back In" color={C.blue} onClick={()=>setScreen("home")}/>
        <div style={{height:8}}/>
        <Btn label="✅ Done for the Day" color={C.dark} onClick={()=>setScreen("home")}/>
      </Shell>
    );
  }

  if(screen==="history"){
    const days=store.days||{};
    const sorted=Object.keys(days).sort().reverse();
    return(
      <Shell title="Work History" employee={emp} onBack={()=>setScreen("home")} toast={toast}>
        {sorted.length===0&&<div style={{textAlign:"center",color:C.sub,marginTop:40}}>No history yet.</div>}
        {sorted.map(k=>{
          const day=days[k]; const sess=day.sessions||[];
          return(
            <Card key={k}>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:10}}>
                <div style={{fontWeight:800,color:C.text,fontSize:15}}>{k}</div>
                <div style={{fontSize:13,color:C.blue,fontWeight:700}}>{fmtDur(dayNetMs(day))} total</div>
              </div>
              {sess.filter(s=>s.clockOut).map((s,i)=>{
                const isEd=editKey===k&&editIdx===i;
                return(
                  <div key={i} style={{marginBottom:10,paddingBottom:10,borderBottom:`1px solid ${C.border}`}}>
                    <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:6}}>
                      <div style={{fontSize:12,fontWeight:700,color:C.blue}}>Session {i+1}</div>
                      <button onClick={()=>{
                          if(isEd){setEditKey(null);setEditIdx(null);}
                          else{
                            setEditKey(k);setEditIdx(i);
                            setECI(s.clockIn?new Date(s.clockIn).toTimeString().slice(0,5):"");
                            setECO(s.clockOut?new Date(s.clockOut).toTimeString().slice(0,5):"");
                            setETH(s.travelHours||"");setETM(s.travelMiles||"");
                            setELM(s.lunchMin!=null?String(s.lunchMin):"");
                          }
                        }}
                        style={{background:isEd?C.red:C.blue,color:"#fff",border:"none",
                          borderRadius:8,padding:"4px 12px",fontSize:11,fontWeight:700,cursor:"pointer"}}>
                        {isEd?"Cancel":"Edit"}
                      </button>
                    </div>
                    {isEd?(
                      <div>
                        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
                          {[["In",eCI,setECI],["Out",eCO,setECO]].map(([l,v,sv])=>(
                            <div key={l}>
                              <div style={{fontSize:12,color:C.sub,marginBottom:3}}>Clock {l}</div>
                              <input type="time" value={v} onChange={x=>sv(x.target.value)}
                                style={{width:"100%",padding:"9px",borderRadius:8,
                                  border:`1px solid ${C.border}`,fontSize:14,boxSizing:"border-box"}}/>
                            </div>
                          ))}
                        </div>
                        <div style={{display:"grid",gridTemplateColumns:"1fr 1fr 1fr",gap:8,marginBottom:10}}>
                          {[["Lunch min",eLM,setELM],["Travel hrs",eTH,setETH],["Miles",eTM,setETM]].map(([l,v,sv])=>(
                            <div key={l}>
                              <div style={{fontSize:12,color:C.sub,marginBottom:3}}>{l}</div>
                              <input type="number" value={v} onChange={x=>sv(x.target.value)}
                                style={{width:"100%",padding:"9px",borderRadius:8,
                                  border:`1px solid ${C.border}`,fontSize:14,boxSizing:"border-box"}}/>
                            </div>
                          ))}
                        </div>
                        <Btn label="💾 Save" color={C.red} sm
                          onClick={()=>{
                            const b=k+"T";
                            const ci=eCI?new Date(b+eCI+":00").getTime():s.clockIn;
                            const co=eCO?new Date(b+eCO+":00").getTime():s.clockOut;
                            const log=[...(s.modifiedLog||[]),{modifiedAt:Date.now(),by:emp,
                              prev:{clockIn:s.clockIn,clockOut:s.clockOut,lunchMin:s.lunchMin,
                                travelHours:s.travelHours,travelMiles:s.travelMiles}}];
                            patchSesh(k,i,{clockIn:ci,clockOut:co,
                              lunchMin:parseInt(eLM)||0,travelHours:eTH,travelMiles:eTM,modifiedLog:log});
                            setEditKey(null);setEditIdx(null);
                            toast_("✅ Session updated.");
                          }}/>
                      </div>
                    ):(
                      <>
                        <Row label="In / Out" value={`${fmtTime(s.clockIn)} → ${fmtTime(s.clockOut)}`}/>
                        <Row label="Lunch"    value={s.lunchMin?`${s.lunchMin} min`:"None"}/>
                        <Row label="Net"      value={fmtDur(netMs(s))} accent={C.blue}/>
                        {s.travelHours&&<Row label="Travel" value={`${s.travelHours} hrs · ${s.travelMiles||0} mi`}/>}
                        {s.modifiedLog?.length>0&&<div style={{marginTop:4,fontSize:11,color:C.red,fontWeight:600}}>✏️ Modified {s.modifiedLog.length}×</div>}
                      </>
                    )}
                  </div>
                );
              })}
              <Row label="Day Total" value={fmtDur(dayNetMs(day))} accent={C.red}/>
            </Card>
          );
        })}
      </Shell>
    );
  }

  if(screen==="admin"){
    if(!unlocked) return(
      <Shell title="Admin Access" onBack={()=>setScreen("home")} toast={toast}>
        <Card>
          <div style={{fontSize:17,fontWeight:800,color:C.text,marginBottom:16,textAlign:"center"}}>Enter Admin PIN</div>
          <input type="password" placeholder="PIN" value={pin} onChange={e=>setPin(e.target.value)}
            onKeyDown={e=>{if(e.key==="Enter"&&pin===(cfg.pin||"1234")){setUnlocked(true);setPin("");}}}
            style={{width:"100%",padding:"16px",fontSize:22,textAlign:"center",borderRadius:10,
              border:`2px solid ${C.border}`,boxSizing:"border-box",marginBottom:16,letterSpacing:6}}/>
          <Btn label="Unlock" color={C.red}
            onClick={()=>{
              if(pin===(cfg.pin||"1234")){setUnlocked(true);setPin("");}
              else toast_("❌ Incorrect PIN");
            }}/>
          <div style={{marginTop:10,textAlign:"center",fontSize:12,color:C.sub}}>Default PIN: 1234</div>
        </Card>
      </Shell>
    );

    const tabs=[{id:"employees",icon:"👥",label:"Employees"},{id:"email",icon:"📧",label:"Email"},
                {id:"payroll",icon:"📊",label:"Payroll"},{id:"settings",icon:"🔒",label:"Settings"}];
    const pt=payTotals(pStart,pEnd);
    const wk=thisWeekRange(),lwk=lastWeekRange();
    const fEmps=employees.filter(e=>e.toLowerCase().includes(empSrch.toLowerCase()));

    return(
      <Shell title="Admin Panel" onBack={()=>{setUnlocked(false);setScreen("home");}} toast={toast}>
        <div style={{display:"grid",gridTemplateColumns:"repeat(4,1fr)",gap:4,marginBottom:16}}>
          {tabs.map(t=>(
            <button key={t.id} onClick={()=>{setATab(t.id);setConfDel(null);}}
              style={{background:aTab===t.id?C.blue:"#fff",color:aTab===t.id?"#fff":C.sub,
                border:`2px solid ${aTab===t.id?C.blue:C.border}`,borderRadius:10,
                padding:"8px 4px",cursor:"pointer",fontSize:11,fontWeight:700,textAlign:"center",lineHeight:1.4}}>
              <div style={{fontSize:18}}>{t.icon}</div>{t.label}
            </button>
          ))}
        </div>

        {aTab==="employees"&&(
          <div>
            <Card style={{borderLeft:`4px solid ${C.green}`}}>
              <div style={{fontWeight:800,color:C.text,fontSize:16,marginBottom:4}}>➕ Add Employee</div>
              <div style={{fontSize:13,color:C.sub,marginBottom:14}}>Appears in sign-in list immediately.</div>
              <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:10}}>
                <div>
                  <div style={{fontSize:13,fontWeight:700,color:C.sub,marginBottom:5}}>First Name</div>
                  <input value={nFirst} onChange={e=>setNFirst(e.target.value)} placeholder="First"
                    onKeyDown={e=>e.key==="Enter"&&document.getElementById("ln")?.focus()}
                    style={{width:"100%",padding:"12px",fontSize:15,borderRadius:10,
                      border:`2px solid ${C.border}`,boxSizing:"border-box"}}/>
                </div>
                <div>
                  <div style={{fontSize:13,fontWeight:700,color:C.sub,marginBottom:5}}>Last Name</div>
                  <input id="ln" value={nLast} onChange={e=>setNLast(e.target.value)} placeholder="Last"
                    onKeyDown={e=>e.key==="Enter"&&addEmp()}
                    style={{width:"100%",padding:"12px",fontSize:15,borderRadius:10,
                      border:`2px solid ${C.border}`,boxSizing:"border-box"}}/>
                </div>
              </div>
              <Btn label="Add Employee" color={C.green} disabled={!nFirst.trim()||!nLast.trim()} onClick={addEmp}/>
            </Card>
            <Card>
              <div style={{display:"flex",justifyContent:"space-between",alignItems:"center",marginBottom:12}}>
                <div style={{fontWeight:800,color:C.text,fontSize:16}}>👥 Current Employees</div>
                <div style={{background:C.blue,color:"#fff",borderRadius:20,padding:"3px 10px",fontSize:13,fontWeight:700}}>{employees.length}</div>
              </div>
              <input value={empSrch} onChange={e=>setEmpSrch(e.target.value)} placeholder="🔍 Search..."
                style={{width:"100%",padding:"10px 12px",fontSize:14,borderRadius:10,
                  border:`2px solid ${C.border}`,boxSizing:"border-box",marginBottom:12}}/>
              {fEmps.map(name=>{
                const isDel=confDel===name;
                return(
                  <div key={name} style={{display:"flex",alignItems:"center",
                    padding:"10px 0",borderBottom:`1px solid ${C.border}`,gap:8}}>
                    <div style={{width:36,height:36,borderRadius:"50%",flexShrink:0,
                      background:`linear-gradient(135deg,${C.blue},${C.dark})`,
                      display:"flex",alignItems:"center",justifyContent:"center",
                      color:"#fff",fontWeight:800,fontSize:13}}>
                      {name.split(" ").map(p=>p[0]).join("").slice(0,2).toUpperCase()}
                    </div>
                    <div style={{flex:1,fontSize:15,fontWeight:600,color:C.text}}>{name}</div>
                    {isDel?(
                      <div style={{display:"flex",gap:6}}>
                        <button onClick={()=>delEmp(name)} style={{background:C.red,color:"#fff",border:"none",
                          borderRadius:8,padding:"5px 10px",fontSize:12,fontWeight:700,cursor:"pointer"}}>Confirm</button>
                        <button onClick={()=>setConfDel(null)} style={{background:C.gray,color:C.sub,
                          border:`1px solid ${C.border}`,borderRadius:8,padding:"5px 10px",
                          fontSize:12,fontWeight:700,cursor:"pointer"}}>Cancel</button>
                      </div>
                    ):(
                      <button onClick={()=>delEmp(name)} style={{background:"none",color:C.red,
                        border:`1px solid ${C.red}`,borderRadius:8,padding:"5px 12px",
                        fontSize:12,fontWeight:700,cursor:"pointer"}}>Remove</button>
                    )}
                  </div>
                );
              })}
            </Card>
          </div>
        )}

        {aTab==="email"&&(
          <Card style={{borderLeft:`4px solid ${C.red}`}}>
            <div style={{fontWeight:800,color:C.text,fontSize:16,marginBottom:4}}>📧 Weekly Email</div>
            <div style={{fontSize:13,color:C.sub,marginBottom:14}}>Auto-sends every Friday at 5 PM.</div>
            <div style={{background:C.gray,borderRadius:10,padding:12,marginBottom:14,fontSize:12,color:C.sub,lineHeight:1.7}}>
              <strong style={{color:C.text}}>Setup:</strong><br/>
              1. <strong>emailjs.com</strong> → free account<br/>
              2. Add Gmail → copy <em>Service ID</em><br/>
              3. Create template → add <code style={{background:"#e8f4fd",padding:"1px 4px",borderRadius:3}}>{"{{csv_data}}"}</code> → copy <em>Template ID</em><br/>
              4. Account → API Keys → copy <em>Public Key</em>
            </div>
            <Inp label="Service ID"      value={cfg.serviceId}    onChange={e=>saveCfg({serviceId:e.target.value})}    placeholder="service_xxxxxxx"/>
            <Inp label="Template ID"     value={cfg.templateId}   onChange={e=>saveCfg({templateId:e.target.value})}   placeholder="template_xxxxxxx"/>
            <Inp label="Public Key"      value={cfg.publicKey}    onChange={e=>saveCfg({publicKey:e.target.value})}     placeholder="xxxxxxxxxxxxxxxxxxxx"/>
            <Inp label="Manager's Email" value={cfg.managerEmail} onChange={e=>saveCfg({managerEmail:e.target.value})} placeholder="manager@company.com"/>
            <div style={{display:"flex",alignItems:"center",gap:10,marginBottom:16}}>
              <input type="checkbox" id="auto" checked={!!cfg.autoSendFriday}
                onChange={e=>saveCfg({autoSendFriday:e.target.checked})} style={{width:18,height:18,cursor:"pointer"}}/>
              <label htmlFor="auto" style={{fontSize:14,fontWeight:700,color:C.text,cursor:"pointer"}}>
                Auto-send every Friday at 5 PM
              </label>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
              <Btn label={sending?"…":"📤 This Week"} color={C.blue} sm disabled={sending}
                onClick={()=>emailReport(emp||"All",wk.start,wk.end)}/>
              <Btn label={sending?"…":"📤 Last Week"} color={C.dark} sm disabled={sending}
                onClick={()=>emailReport(emp||"All",lwk.start,lwk.end)}/>
            </div>
          </Card>
        )}

        {aTab==="payroll"&&(
          <Card>
            <div style={{fontWeight:800,color:C.text,fontSize:16,marginBottom:12}}>📊 Pay Period</div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:8}}>
              <div>
                <div style={{fontSize:12,color:C.sub,marginBottom:4}}>Start</div>
                <input type="date" value={pStart} onChange={e=>setPStart(e.target.value)}
                  style={{width:"100%",padding:"10px",borderRadius:8,border:`1px solid ${C.border}`,boxSizing:"border-box"}}/>
              </div>
              <div>
                <div style={{fontSize:12,color:C.sub,marginBottom:4}}>End</div>
                <input type="date" value={pEnd} onChange={e=>setPEnd(e.target.value)}
                  style={{width:"100%",padding:"10px",borderRadius:8,border:`1px solid ${C.border}`,boxSizing:"border-box"}}/>
              </div>
            </div>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8,marginBottom:12}}>
              <Btn label="This Week" color={C.blue} sm onClick={()=>{const r=thisWeekRange();setPStart(r.start);setPEnd(r.end);}}/>
              <Btn label="Last Week" color={C.dark} sm onClick={()=>{const r=lastWeekRange();setPStart(r.start);setPEnd(r.end);}}/>
            </div>
            {pStart&&pEnd&&(
              <Card style={{background:C.gray,marginBottom:12}}>
                <div style={{fontWeight:700,fontSize:13,color:C.text,marginBottom:6}}>
                  {pt.count} day(s) · {pStart} → {pEnd}
                </div>
                <Row label="Net Work"     value={fmtDur(pt.net)}/>
                <Row label="Travel Hours" value={`${pt.th.toFixed(2)} hrs`}/>
                <Row label="Travel Miles" value={`${pt.tm.toFixed(2)} mi`}/>
              </Card>
            )}
            <Inp label="Employee Name" value={pEmp} onChange={e=>setPEmp(e.target.value)} placeholder="Employee name"/>
            <div style={{display:"grid",gridTemplateColumns:"1fr 1fr",gap:8}}>
              <Btn label="⬇️ CSV" color={C.red} disabled={!pStart||!pEnd||!pEmp} onClick={()=>dlCSV(pEmp,pStart,pEnd)}/>
              <Btn label={sending?"…":"📧 Email"} color={C.blue}
                disabled={sending||!pStart||!pEnd||!pEmp} onClick={()=>emailReport(pEmp,pStart,pEnd)}/>
            </div>
          </Card>
        )}

        {aTab==="settings"&&(
          <Card>
            <div style={{fontWeight:800,color:C.text,fontSize:16,marginBottom:12}}>🔒 Admin PIN</div>
            <Inp label="New PIN" type="password" value={cfg.pin||""}
              onChange={e=>saveCfg({pin:e.target.value})} placeholder="Default: 1234"/>
            <div style={{fontSize:12,color:C.sub,marginBottom:24}}>Saves immediately.</div>
            <div style={{fontWeight:800,color:C.text,fontSize:16,marginBottom:8}}>🗑️ Reset All Data</div>
            <div style={{fontSize:13,color:C.sub,marginBottom:12}}>Permanently deletes all records.</div>
            <Btn label="Reset All Data" color={C.red} sm
              onClick={()=>{
                if(window.confirm("Delete ALL data permanently?")){
                  localStorage.removeItem(SK); window.location.reload();
                }
              }}/>
          </Card>
        )}
      </Shell>
    );
  }

  return <div style={{padding:40,textAlign:"center",color:C.sub}}>Loading…</div>;
}
